--
-- Name: assign_rate_types_to_area(integer, integer[], uuid); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.assign_rate_types_to_area(p_area_id integer, rate_type_ids integer[], p_user_id uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    rt_id INTEGER;
    inserted_count INTEGER := 0;
BEGIN
    FOREACH rt_id IN ARRAY rate_type_ids
    LOOP
        INSERT INTO area_rate_types (area_id, rate_type_id, created_by)
        VALUES (p_area_id, rt_id, p_user_id)
        ON CONFLICT (area_id, rate_type_id) DO NOTHING;
        inserted_count := inserted_count + 1;
    END LOOP;
    RETURN inserted_count;
END;
$$;


ALTER FUNCTION public.assign_rate_types_to_area(p_area_id integer, rate_type_ids integer[], p_user_id uuid) OWNER TO acs_user;

--
-- Name: verification_attachments_freeze_address(); Type: FUNCTION; Schema: public; Owner: acs_user
-- 2026-04-21: protects evidence integrity. Once reverse_geocoded_address
-- has been stored on an attachment row, any subsequent UPDATE that would
-- change the column (to a different value or back to NULL) is rejected
-- by this trigger. The only allowed transition is NULL -> value
-- (the first-view resolve done by the backend geocode endpoint).
--

CREATE FUNCTION public.verification_attachments_freeze_address() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.reverse_geocoded_address IS NOT NULL
     AND NEW.reverse_geocoded_address IS DISTINCT FROM OLD.reverse_geocoded_address
  THEN
    RAISE EXCEPTION
      'verification_attachments.reverse_geocoded_address is immutable once set (attachment id=%)',
      OLD.id
      USING HINT = 'The reverse-geocoded address is frozen for evidence integrity. Create a separate audited override column if correction is genuinely needed.';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.verification_attachments_freeze_address() OWNER TO acs_user;


--
-- Name: audit_territory_assignment_changes(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.audit_territory_assignment_changes() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        INSERT INTO territory_assignment_audit (
            user_id, assignment_type, assignment_id, action,
            previous_data, new_data, performed_by
        ) VALUES (
            NEW.user_id,
            CASE WHEN TG_TABLE_NAME = 'user_pincode_assignments' THEN 'PINCODE' ELSE 'AREA' END,
            NEW.id, 'ASSIGNED', NULL,
            json_build_object('assigned_by', NEW.assigned_by, 'is_active', NEW.is_active),
            NEW.assigned_by
        );
    ELSIF TG_OP = 'UPDATE' THEN
        INSERT INTO territory_assignment_audit (
            user_id, assignment_type, assignment_id, action,
            previous_data, new_data, performed_by
        ) VALUES (
            NEW.user_id,
            CASE WHEN TG_TABLE_NAME = 'user_pincode_assignments' THEN 'PINCODE' ELSE 'AREA' END,
            NEW.id, 'UPDATED',
            json_build_object('is_active', OLD.is_active),
            json_build_object('is_active', NEW.is_active, 'assigned_by', NEW.assigned_by),
            NEW.assigned_by
        );
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.audit_territory_assignment_changes() OWNER TO acs_user;

--
-- Name: cleanup_performance_data(integer); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.cleanup_performance_data(days_to_keep integer DEFAULT 30) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    deleted_count INTEGER;
BEGIN
    -- Clean up old performance metrics
    DELETE FROM performance_metrics WHERE timestamp < NOW() - INTERVAL '1 day' * days_to_keep;
    GET DIAGNOSTICS deleted_count = ROW_COUNT;
    
    -- Clean up old query performance data
    DELETE FROM query_performance WHERE timestamp < NOW() - INTERVAL '1 day' * days_to_keep;
    
    -- Clean up old error logs (keep longer for analysis)
    DELETE FROM error_logs WHERE timestamp < NOW() - INTERVAL '1 day' * (days_to_keep * 2);
    
    -- Clean up old system health metrics
    DELETE FROM system_health_metrics WHERE timestamp < NOW() - INTERVAL '1 day' * days_to_keep;
    
    RETURN deleted_count;
END;
$$;


ALTER FUNCTION public.cleanup_performance_data(days_to_keep integer) OWNER TO acs_user;

--
-- Name: FUNCTION cleanup_performance_data(days_to_keep integer); Type: COMMENT; Schema: public; Owner: acs_user
--

COMMENT ON FUNCTION public.cleanup_performance_data(days_to_keep integer) IS 'Cleans up old performance monitoring data to prevent table bloat';


--
-- Name: create_default_notification_preferences(); Type: FUNCTION; Schema: public; Owner: acs_user
--

