--
-- Name: create_rate_history(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.create_rate_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'UPDATE' AND OLD.amount != NEW.amount THEN
        INSERT INTO rate_history (rate_id, old_amount, new_amount, changed_by)
        VALUES (NEW.id, OLD.amount, NEW.amount, NEW.created_by);
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.create_rate_history() OWNER TO acs_user;

--
-- Name: enforce_verification_task_status_transition(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.enforce_verification_task_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  allowed BOOLEAN;
BEGIN
  -- No-op when status is unchanged. Still runs on UPDATEs that touch
  -- only other columns, which is fine — the early return keeps it
  -- cheap.
  IF NEW.status IS NOT DISTINCT FROM OLD.status THEN
    RETURN NEW;
  END IF;

  -- Allow NULL → any (covers the first INSERT path; technically this
  -- is a BEFORE UPDATE trigger so NULL OLD.status shouldn't happen,
  -- but be explicit).
  IF OLD.status IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT TRUE INTO allowed
  FROM task_status_transitions
  WHERE from_status = OLD.status
    AND to_status   = NEW.status
  LIMIT 1;

  IF allowed IS NULL THEN
    RAISE EXCEPTION 'Invalid verification_task status transition: % -> % (task id %)',
      OLD.status, NEW.status, OLD.id
      USING ERRCODE = '23514';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.enforce_verification_task_status_transition() OWNER TO acs_user;

--
-- Name: generate_task_number(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.generate_task_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.task_number IS NULL THEN
        NEW.task_number := 'VT-' || LPAD(nextval('verification_task_number_seq')::TEXT, 6, '0');
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.generate_task_number() OWNER TO acs_user;

--
-- Name: get_index_usage(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.get_index_usage() RETURNS TABLE(schemaname text, tablename text, indexname text, idx_scan bigint, idx_tup_read bigint, idx_tup_fetch bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        s.schemaname::TEXT,
        s.tablename::TEXT,
        s.indexname::TEXT,
        s.idx_scan,
        s.idx_tup_read,
        s.idx_tup_fetch
    FROM pg_stat_user_indexes s
    ORDER BY s.idx_scan DESC;
END;
$$;


ALTER FUNCTION public.get_index_usage() OWNER TO acs_user;

