--
-- Name: update_case_completion_percentage(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.update_case_completion_percentage() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    total_count INTEGER;
    completed_count INTEGER;
BEGIN
    SELECT COUNT(*), COUNT(*) FILTER (WHERE status = 'COMPLETED')
    INTO total_count, completed_count
    FROM verification_tasks WHERE case_id = NEW.case_id;

    IF total_count > 0 THEN
        UPDATE cases SET
            case_completion_percentage = ROUND((completed_count::numeric / total_count) * 100, 2),
            completed_tasks_count = completed_count,
            total_tasks_count = total_count,
            has_multiple_tasks = (total_count > 1),
            updated_at = NOW()
        WHERE id = NEW.case_id;
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_case_completion_percentage() OWNER TO acs_user;

