--
-- Name: case_assignment_analytics; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.case_assignment_analytics AS
 SELECT date_trunc('day'::text, assigned_at) AS assignment_date,
    count(*) AS total_assignments,
    count(DISTINCT COALESCE(case_uuid, case_id)) AS unique_cases,
    count(DISTINCT to_user_id) AS unique_assignees,
    count(
        CASE
            WHEN (from_user_id IS NOT NULL) THEN 1
            ELSE NULL::integer
        END) AS reassignments,
    count(
        CASE
            WHEN (batch_id IS NOT NULL) THEN 1
            ELSE NULL::integer
        END) AS bulk_assignments,
    avg(
        CASE
            WHEN (batch_id IS NOT NULL) THEN ( SELECT case_assignment_queue_status.total_cases AS "totalCases"
               FROM public.case_assignment_queue_status
              WHERE ((case_assignment_queue_status.batch_id)::text = (cah.batch_id)::text)
             LIMIT 1)
            ELSE NULL::integer
        END) AS avg_bulk_size
   FROM public.case_assignment_history cah
  WHERE (assigned_at IS NOT NULL)
  GROUP BY (date_trunc('day'::text, assigned_at))
  ORDER BY (date_trunc('day'::text, assigned_at)) DESC;


ALTER VIEW public.case_assignment_analytics OWNER TO acs_user;

--
-- Name: VIEW case_assignment_analytics; Type: COMMENT; Schema: public; Owner: acs_user
--

COMMENT ON VIEW public.case_assignment_analytics IS 'Analytics view for assignment operations';


