--
-- Name: document_type_rates_view; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.document_type_rates_view AS
 SELECT dtr.id,
    dtr.client_id,
    dtr.product_id,
    dtr.document_type_id,
    dtr.amount,
    dtr.currency,
    dtr.is_active,
    dtr.effective_from,
    dtr.effective_to,
    dtr.created_by,
    dtr.created_at,
    dtr.updated_at,
    c.name AS client_name,
    c.code AS client_code,
    p.name AS product_name,
    p.code AS product_code,
    kdt.name AS document_type_name,
    kdt.code AS document_type_code,
    kdt.category AS document_type_category
   FROM (((public.document_type_rates dtr
     JOIN public.clients c ON ((dtr.client_id = c.id)))
     JOIN public.products p ON ((dtr.product_id = p.id)))
     JOIN public.kyc_document_types kdt ON ((dtr.document_type_id = kdt.id)));


ALTER VIEW public.document_type_rates_view OWNER TO acs_user;

