    CONSTRAINT users_avg_case_completion_days_check CHECK ((avg_case_completion_days >= (0)::numeric)),
    CONSTRAINT users_performance_rating_check CHECK (((performance_rating >= (0)::numeric) AND (performance_rating <= (5)::numeric))),
