--
-- Name: mobile_sync_analytics; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.mobile_sync_analytics AS
 SELECT date_trunc('hour'::text, last_sync_at) AS sync_hour,
    count(*) AS total_syncs,
    count(DISTINCT user_id) AS unique_users,
    count(DISTINCT device_id) AS unique_devices,
    avg(sync_count) AS avg_sync_count,
    count(
        CASE
            WHEN ((platform)::text = 'iOS'::text) THEN 1
            ELSE NULL::integer
        END) AS ios_syncs,
    count(
        CASE
            WHEN ((platform)::text = 'Android'::text) THEN 1
            ELSE NULL::integer
        END) AS android_syncs
   FROM public.mobile_device_sync mds
  WHERE (last_sync_at >= (now() - '24:00:00'::interval))
  GROUP BY (date_trunc('hour'::text, last_sync_at))
  ORDER BY (date_trunc('hour'::text, last_sync_at)) DESC;


ALTER VIEW public.mobile_sync_analytics OWNER TO acs_user;

