--
-- Name: rate_management_view; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.rate_management_view AS
 SELECT r.id,
    r.client_id,
    c.name AS client_name,
    c.code AS client_code,
    r.product_id,
    p.name AS product_name,
    p.code AS product_code,
    r.verification_type_id,
    vt.name AS verification_type_name,
    vt.code AS verification_type_code,
    r.rate_type_id,
    rt.name AS rate_type_name,
    r.amount,
    r.currency,
    r.is_active,
    r.effective_from,
    r.effective_to,
    r.created_at,
    r.updated_at
   FROM ((((public.rates r
     JOIN public.clients c ON ((r.client_id = c.id)))
     JOIN public.products p ON ((r.product_id = p.id)))
     JOIN public.verification_types vt ON ((r.verification_type_id = vt.id)))
     JOIN public.rate_types rt ON ((r.rate_type_id = rt.id)));


ALTER VIEW public.rate_management_view OWNER TO acs_user;

--
-- Name: rate_type_assignment_view; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.rate_type_assignment_view AS
 SELECT rta.id,
    rta.client_id,
    c.name AS client_name,
    c.code AS client_code,
    rta.product_id,
    p.name AS product_name,
    p.code AS product_code,
    rta.verification_type_id,
    vt.name AS verification_type_name,
    vt.code AS verification_type_code,
    rta.rate_type_id,
    rt.name AS rate_type_name,
    rta.is_active,
    rta.created_at,
    rta.updated_at
   FROM ((((public.rate_type_assignments rta
     JOIN public.clients c ON ((rta.client_id = c.id)))
     JOIN public.products p ON ((rta.product_id = p.id)))
     JOIN public.verification_types vt ON ((rta.verification_type_id = vt.id)))
     JOIN public.rate_types rt ON ((rta.rate_type_id = rt.id)));


