--
-- Name: slow_queries; Type: VIEW; Schema: public; Owner: acs_user
--

CREATE VIEW public.slow_queries AS
 SELECT query_hash,
    query_text,
    avg(execution_time) AS avg_execution_time,
    max(execution_time) AS max_execution_time,
    count(*) AS execution_count,
    max("timestamp") AS last_execution
   FROM public.query_performance
  WHERE (execution_time > (100)::numeric)
  GROUP BY query_hash, query_text
  ORDER BY (avg(execution_time)) DESC;


ALTER VIEW public.slow_queries OWNER TO acs_user;

